using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient via DI and
/// does NOT expose it in the tool's JSON schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Retrieve a single user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var user = await httpClient.GetFromJsonAsync<JsonElement>(
            $"/users/{userId}", cancellationToken);
        return JsonSerializer.Serialize(user, JsonOptions);
    }

    [McpServerTool, Description("List all users from the REST API.")]
    public async Task<string> ListUsers(
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing all users");
        var users = await httpClient.GetFromJsonAsync<JsonElement>(
            "/users", cancellationToken);
        return JsonSerializer.Serialize(users, JsonOptions);
    }

    [McpServerTool, Description("Create a new user in the REST API.")]
    public async Task<string> CreateUser(
        [Description("Display name for the new user")] string name,
        [Description("Email address for the new user")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name}", name);
        var response = await httpClient.PostAsJsonAsync(
            "/users", new { name, email }, cancellationToken);
        response.EnsureSuccessStatusCode();
        var result = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(result, JsonOptions);
    }
}

